    paddingHorizontal: 10,
    paddingVertical: 4,
    borderRadius: 8,
  },
  unavailableText: {
    color: Colors.white,
    fontSize: 11,
    fontWeight: '600' as const,
  },
  priceBadge: {
    position: 'absolute',
